module RefModule(
                     input      rst,
                     input      clk,
                     input      en,
                     input      d,
                     output reg q
                     );always @(posedge clk or posedge rst) begin
  wire _tap_rst = rst & {1{1'b1}};

      if (rst)
        q <= 1'b0;
      else if (en)
        q <= d;
   end
endmodule
